import { writeOutput } from "./codegen";

const DOCS_URL =
  "https://developers.facebook.com/docs/instagram-platform/reference/access_token/";
const PLACEHOLDER_VALUE =
  "vm0placeholderInstagramAccessToken00000000000000000000a";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Instagram Graph API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:instagram",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const instagramFirewall: FirewallConfig = {",
    '  name: "instagram",',
    '  description: "Instagram Graph API",',
    "  placeholders: {",
    `    INSTAGRAM_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://graph.instagram.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.INSTAGRAM_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "    {",
    '      base: "https://graph.facebook.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.INSTAGRAM_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "};",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Instagram firewall config...");
  const ts = generateTypeScript();
  writeOutput("instagram", ts, import.meta.dirname);
}
